mapper.update:
UPDATE t_sms_send_log
SET result_message = #{errMsg},
    send_status    = #{sendStatus},
    send_time      = #{sendTime}
WHERE biz_id = #{bizId}

mapper.select:
SELECT 1
FROM t_order_car_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  AND order_status = 1 LIMIT 1

SELECT 1
FROM t_order_alcohol_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  AND order_status = 1 LIMIT 1

SELECT 1
FROM t_order_drum_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  AND order_status = 1 LIMIT 1

SELECT *
FROM t_order_car_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  and order_status = 1
ORDER BY order_id ASC LIMIT 10

SELECT *
FROM t_order_alcohol_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  and order_status = 1
ORDER BY order_id ASC LIMIT 10

SELECT *
FROM t_order_drum_info
WHERE order_id BETWEEN #{startOrderId} AND #{endOrderId}
  AND machine_no = #{machineNo}
  and order_status = 1
ORDER BY order_id ASC LIMIT 10

select *
from t_user
where user_num = #{userNum}
   or user_num = #{agentUserNum}
   or user_num = #{parentUserNum}

select trad_create_time
from t_order_car_info
where order_id = #{midOrderId}

select trad_create_time
from t_order_alcohol_info
where order_id = #{midOrderId}

select trad_create_time
from t_order_drum_info
where order_id = #{midOrderId}

select *
from t_check_log
where machine_no = #{machineNo}
order by log_id desc limit 1;

select login_name
from t_tool_user
where login_name = #{username}
  and password = #{password}
  and is_delete = 0
